(() => {
                          const detected = placeholders.map((p) => p.replace(/^<<|>>$/g, ""));
                          const required = ["Phone Number", "Email"];
                          if (multiTemplate) required.unshift("Role");
                          const all = [...detected];
                          for (const rh of required) {
                            if (!all.some((h) => h.toLowerCase() === rh.toLowerCase())) {
                              all.push(rh);
                            }
                          }
                          return all.join(", ");
                        })

